INSERT INTO birds (common_name, scientific_name, family, conservation_status, size_category, average_length_cm, average_weight_grams, habitat, diet, migratory, description, icon, color_hex) VALUES
('Bald Eagle', 'Haliaeetus leucocephalus', 'Accipitridae', 'LEAST_CONCERN', 'LARGE', 80.0, 4500.0, 'Large lakes, rivers and coastlines near tall trees', 'Fish, waterfowl, carrion', TRUE, 'The national bird of the United States, this powerful raptor has a striking white head and tail that develop around five years of age. Often seen soaring near open water or perched in tall snags while watching for fish.', '🦅', '#4A6B8A'),
('Golden Eagle', 'Aquila chrysaetos', 'Accipitridae', 'LEAST_CONCERN', 'LARGE', 84.0, 4500.0, 'Mountains, cliffs and open grasslands', 'Mammals, birds, carrion', FALSE, 'One of the largest and fastest raptors in the world, the Golden Eagle hunts hares, marmots and ground squirrels by sweeping low over open terrain on broad, dark wings.', '🦅', '#8A6E4A'),
('Peregrine Falcon', 'Falco peregrinus', 'Falconidae', 'LEAST_CONCERN', 'MEDIUM', 42.0, 800.0, 'Cliffs, coastlines and increasingly city skyscrapers', 'Birds caught in flight', TRUE, 'The fastest animal on the planet, capable of exceeding 300 km/h in a hunting stoop. Once endangered by pesticides, it has made a remarkable comeback and now nests on bridges and buildings worldwide.', '🦅', '#6B7280'),
('Great Horned Owl', 'Bubo virginianus', 'Strigidae', 'LEAST_CONCERN', 'LARGE', 55.0, 1400.0, 'Forests, deserts, wetlands and urban parks', 'Small mammals, birds, reptiles', FALSE, 'A formidable nocturnal predator with prominent ear tufts and piercing yellow eyes. Its deep, resonant hooting is one of the most recognizable sounds of the night.', '🦉', '#8B5E3C'),
('Snowy Owl', 'Bubo scandiacus', 'Strigidae', 'VULNERABLE', 'LARGE', 65.0, 1800.0, 'Arctic tundra, and open fields and coastlines in winter', 'Lemmings, voles, small mammals', TRUE, 'A striking white owl of the high Arctic that occasionally irrupts south in large numbers during winters when lemming populations crash. Males become almost pure white with age.', '🦉', '#A8B8C8'),
('Barn Owl', 'Tyto alba', 'Tytonidae', 'LEAST_CONCERN', 'MEDIUM', 35.0, 470.0, 'Farmland, grasslands and old barns', 'Small rodents', FALSE, 'A ghostly pale owl with a heart-shaped facial disc that funnels sound to its acute ears, allowing it to hunt rodents in complete darkness by sound alone.', '🦉', '#D8C9A3'),
('Mallard', 'Anas platyrhynchos', 'Anatidae', 'LEAST_CONCERN', 'MEDIUM', 58.0, 1100.0, 'Ponds, lakes, marshes and rivers', 'Aquatic plants, insects, small fish', TRUE, 'The most familiar duck in the world and ancestor of nearly all domestic duck breeds. Males sport an iridescent green head while females are mottled brown for camouflage on the nest.', '🦆', '#2E7D5B'),
('Wood Duck', 'Aix sponsa', 'Anatidae', 'LEAST_CONCERN', 'MEDIUM', 47.0, 680.0, 'Wooded swamps, marshes and slow streams', 'Seeds, fruits, insects', TRUE, 'Widely considered one of the most colorful waterfowl species, the male''s iridescent plumage and sweeping crest make it a favorite among wildlife photographers. Nests in tree cavities near water.', '🦆', '#7C4A8A'),
('Canada Goose', 'Branta canadensis', 'Anatidae', 'LEAST_CONCERN', 'LARGE', 100.0, 4500.0, 'Lakes, ponds, parks and grain fields', 'Grasses, grains, aquatic plants', TRUE, 'Recognized by its black head and neck with a white chinstrap, this familiar goose travels in large V-shaped flocks and has adapted remarkably well to urban parks and golf courses.', '🦢', '#5B5B5B'),
('Trumpeter Swan', 'Cygnus buccinator', 'Anatidae', 'LEAST_CONCERN', 'LARGE', 150.0, 11000.0, 'Large lakes, rivers and marshes', 'Aquatic vegetation', TRUE, 'North America''s largest native waterfowl species, named for its deep, resonant call. Once nearly hunted to extinction, conservation efforts have helped populations recover across the continent.', '🦢', '#DCE6F1'),
('American Robin', 'Turdus migratorius', 'Turdidae', 'LEAST_CONCERN', 'SMALL', 25.0, 77.0, 'Gardens, parks, woodlands and lawns', 'Earthworms, insects, fruit', TRUE, 'A familiar sign of spring across North America, easily identified by its warm orange breast and cheerful song. Often seen hopping across lawns in search of earthworms.', '🐦', '#C1440E'),
('Northern Cardinal', 'Cardinalis cardinalis', 'Cardinalidae', 'LEAST_CONCERN', 'SMALL', 21.0, 45.0, 'Woodland edges, gardens and shrubland', 'Seeds, fruits, insects', FALSE, 'The vivid red plumage and crest of the male make this one of the most recognizable backyard birds in eastern North America. Both sexes sing, which is unusual among songbirds.', '🐦', '#C1272D'),
('Blue Jay', 'Cyanocitta cristata', 'Corvidae', 'LEAST_CONCERN', 'SMALL', 28.0, 85.0, 'Deciduous and mixed forests, suburban yards', 'Acorns, seeds, insects', FALSE, 'A bold and intelligent corvid known for its striking blue, white and black plumage and its loud, varied calls, including convincing imitations of hawks.', '🐦', '#3F6CA8'),
('House Sparrow', 'Passer domesticus', 'Passeridae', 'LEAST_CONCERN', 'SMALL', 16.0, 30.0, 'Urban and agricultural areas worldwide', 'Seeds, grains, insects', FALSE, 'One of the most widespread wild birds on the planet, having followed human settlement to nearly every continent. Gregarious and adaptable, often seen in noisy flocks.', '🐤', '#A88A5E'),
('European Starling', 'Sturnus vulgaris', 'Sturnidae', 'LEAST_CONCERN', 'SMALL', 21.0, 82.0, 'Urban areas, farmland and woodlands', 'Insects, fruit, grain', TRUE, 'Famous for forming massive, swirling flocks called murmurations at dusk. Up close, its glossy black plumage shimmers with iridescent purples and greens, speckled with white in winter.', '🐦‍⬛', '#4B4B6B'),
('Scarlet Macaw', 'Ara macao', 'Psittacidae', 'LEAST_CONCERN', 'LARGE', 85.0, 1000.0, 'Lowland tropical rainforest', 'Fruits, nuts, seeds', FALSE, 'A spectacular, long-tailed parrot with brilliant red, yellow and blue plumage. Pairs mate for life and can often be heard before they are seen, calling loudly as they fly above the canopy.', '🦜', '#D7263D'),
('Rainbow Lorikeet', 'Trichoglossus moluccanus', 'Psittaculidae', 'LEAST_CONCERN', 'SMALL', 27.0, 130.0, 'Rainforest, woodlands and coastal scrub', 'Nectar, pollen, fruit', FALSE, 'A dazzlingly colorful parrot with a brush-tipped tongue adapted for feeding on nectar and pollen. Noisy and gregarious, often seen in fast-flying, screeching flocks.', '🦜', '#1FA37A'),
('Emperor Penguin', 'Aptenodytes forsteri', 'Spheniscidae', 'NEAR_THREATENED', 'LARGE', 115.0, 25000.0, 'Antarctic pack ice and coastal waters', 'Fish, krill, squid', FALSE, 'The tallest and heaviest of all living penguins, famous for enduring the brutal Antarctic winter to incubate a single egg balanced on its feet for around two months.', '🐧', '#2B3A55'),
('African Penguin', 'Spheniscus demersus', 'Spheniscidae', 'ENDANGERED', 'MEDIUM', 63.0, 3000.0, 'Rocky coastlines and offshore islands', 'Sardines, anchovies, squid', FALSE, 'Also known as the jackass penguin for its donkey-like braying call, this southern African species nests in burrows and has suffered steep population declines from overfishing and habitat loss.', '🐧', '#1C1C1C'),
('American Flamingo', 'Phoenicopterus ruber', 'Phoenicopteridae', 'LEAST_CONCERN', 'LARGE', 140.0, 2800.0, 'Shallow lagoons, mudflats and salt pans', 'Algae, small crustaceans', FALSE, 'Famous for its vivid pink plumage, derived from carotenoid pigments in its diet of algae and brine shrimp. Feeds by sweeping its specially adapted bill upside-down through shallow water.', '🦩', '#E0558C'),
('Wild Turkey', 'Meleagris gallopavo', 'Phasianidae', 'LEAST_CONCERN', 'LARGE', 110.0, 8000.0, 'Hardwood forests and woodland edges', 'Acorns, seeds, insects', FALSE, 'A large, ground-dwelling bird native to North America. Males display an iridescent bronze-green sheen and fan their tail feathers dramatically during courtship.', '🦃', '#7A4B2A'),
('Mourning Dove', 'Zenaida macroura', 'Columbidae', 'LEAST_CONCERN', 'SMALL', 31.0, 120.0, 'Open woodlands, fields and suburban areas', 'Seeds and grains', TRUE, 'Named for its soft, mournful cooing call, this slender, fast-flying dove is one of the most abundant and widespread birds in North America.', '🕊️', '#B8AFA3'),
('Indian Peafowl', 'Pavo cristatus', 'Phasianidae', 'LEAST_CONCERN', 'LARGE', 200.0, 5000.0, 'Open forests and farmland near water', 'Seeds, insects, small reptiles', FALSE, 'The males of this species, known as peacocks, are famous for their iridescent blue-green train of tail feathers, fanned out and shaken in an elaborate courtship display.', '🦚', '#1F6F5C'),
('Whooping Crane', 'Grus americana', 'Gruidae', 'ENDANGERED', 'LARGE', 150.0, 7000.0, 'Marshes, wetlands and prairie potholes', 'Crustaceans, fish, grains', TRUE, 'North America''s tallest bird and one of its rarest, brought back from the brink of extinction through decades of intensive conservation. Pairs perform an elegant, leaping courtship dance.', '🐦', '#E8E4DC'),
('California Condor', 'Gymnogyps californianus', 'Cathartidae', 'CRITICALLY_ENDANGERED', 'LARGE', 130.0, 10000.0, 'Mountain cliffs, canyons and open grasslands', 'Carrion', FALSE, 'With a wingspan approaching three meters, this is the largest flying bird in North America. Every wild individual is part of an intensively monitored population descended from a captive-breeding program that began with just 27 birds.', '🦅', '#5A3E36');
